<section class="card"><form method="post" action="/quotations<?= !empty($row['id'])?'/'.e($row['id']):'' ?>"><?= csrf_field() ?><div class="form-grid"><label>Quotation No<input name="quotation_number" value="<?= e($row['quotation_number'] ?? '') ?>" placeholder="Auto"></label><label>Customer<select name="customer_id"><?php foreach($customers as $c): ?><option value="<?= e($c['id']) ?>" <?= ($row['customer_id'] ?? '')==$c['id']?'selected':'' ?>><?= e($c['company_name']) ?></option><?php endforeach; ?></select></label><label>Date<input type="date" name="quotation_date" value="<?= e($row['quotation_date'] ?? date('Y-m-d')) ?>"></label><label>Valid Till<input type="date" name="valid_till" value="<?= e($row['valid_till'] ?? date('Y-m-d', strtotime('+15 days'))) ?>"></label><label>Currency<select name="currency_id"><?php foreach($currencies as $c): ?><option value="<?= e($c['id']) ?>" <?= ($row['currency_id'] ?? '')==$c['id']?'selected':'' ?>><?= e($c['code']) ?></option><?php endforeach; ?></select></label><label>Status<select name="quotation_status_id"><?php foreach($statuses as $s): ?><option value="<?= e($s['id']) ?>" <?= ($row['quotation_status_id'] ?? 1)==$s['id']?'selected':'' ?>><?= e($s['name']) ?></option><?php endforeach; ?></select></label></div><h3>Line Items</h3><table id="items"><tr><th>Description</th><th>Qty</th><th>Rate</th><th>Disc Type</th><th>Disc</th><th>Tax %</th></tr><?php $items=$items ?: [[]]; foreach($items as $it): ?><tr><td><input name="description[]" value="<?= e($it['description'] ?? '') ?>"><input type="hidden" name="product_id[]" value="<?= e($it['product_id'] ?? '') ?>"><input type="hidden" name="product_code_snapshot[]" value="<?= e($it['product_code_snapshot'] ?? '') ?>"><input type="hidden" name="unit_id[]" value="<?= e($it['unit_id'] ?? '') ?>"><input type="hidden" name="tax_id[]" value="<?= e($it['tax_id'] ?? '') ?>"></td><td><input type="number" step="0.001" name="quantity[]" value="<?= e($it['quantity'] ?? 1) ?>"></td><td><input type="number" step="0.01" name="rate[]" value="<?= e($it['rate'] ?? 0) ?>"></td><td><select name="discount_type[]"><option value="fixed">Fixed</option><option value="percent">Percent</option></select></td><td><input type="number" step="0.01" name="discount_value[]" value="<?= e($it['discount_value'] ?? 0) ?>"></td><td><input type="number" step="0.01" name="tax_rate_snapshot[]" value="<?= e($it['tax_rate_snapshot'] ?? 18) ?>"></td></tr><?php endforeach; ?></table><button type="button" onclick="addItem()">Add Item</button><div class="form-grid"><label>Global Discount Type<select name="global_discount_type"><option value="fixed">Fixed</option><option value="percent">Percent</option></select></label><label>Global Discount<input type="number" step="0.01" name="global_discount_value" value="<?= e($row['global_discount_value'] ?? 0) ?>"></label></div><label>Notes<textarea name="notes"><?= e($row['notes'] ?? '') ?></textarea></label><label>Terms<textarea name="terms_conditions"><?= e($row['terms_conditions'] ?? 'Payment 50% advance, balance before dispatch.') ?></textarea></label><button class="primary">Save Quotation</button></form></section>
